const opportunity = $('Fetch Top Opportunities').first().json;
const pageQueries = $input.all().map(i => `${i.json.query} (pos: ${i.json.position}, ${i.json.impressions} impressions)`).join('\n');

const prompt = `You are an SEO strategist for a Hebrew business portal about Israeli business types (עוסק פטור, עוסק מורשה, חברה בעמ).

Parent page: ${opportunity.page_url}
Opportunity type: ${opportunity.opportunity_type}
Top ranking queries for this page:
${pageQueries || 'No data yet'}

Suggest 2-3 NEW Hebrew article ideas that would extend topical authority around this page.
Return ONLY a JSON array, no explanation:
[
  {
    "target_query": "ביטוי חיפוש ראשי",
    "suggested_article_title": "כותרת מאמר מוצעת",
    "search_intent": "informational|commercial|transactional",
    "suggested_angle": "זווית ייחודית של המאמר",
    "why_it_matters": "למה זה חשוב לאתר",
    "internal_links": ["${opportunity.page_url}"]
  }
]

Rules:
- Hebrew content only
- No generic ideas — be specific to Israeli business context
- Prefer commercial intent keywords (מחיר, עלות, כדאי, השוואה)
- Each idea must target a DIFFERENT query`;

return [{ json: {
  opportunity_id: opportunity.id,
  opportunity_page: opportunity.page_url,
  prompt,
  run_id: $('Set Run ID').first().json.run_id
}}];

const claudeResponse = $input.first().json;
const opportunity_id = $('Build Claude Prompt').first().json.opportunity_id;
const page_url = $('Build Claude Prompt').first().json.opportunity_page;

let ideas = [];
try {
  const text = claudeResponse.content[0].text;
  // Extract JSON from response
  const jsonMatch = text.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    ideas = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  console.log('Parse error:', e.message);
  return [{ json: { error: 'parse_failed', opportunity_id } }];
}

return ideas.map(idea => ({
  json: {
    opportunity_id,
    source_page_url: page_url,
    target_query: idea.target_query || '',
    suggested_article_title: idea.suggested_article_title || '',
    search_intent: idea.search_intent || 'informational',
    suggested_angle: idea.suggested_angle || '',
    why_it_matters: idea.why_it_matters || '',
    internal_links: JSON.stringify(idea.internal_links || []),
    status: 'pending'
  }
}));

